using System;
using System.Collections;
using TMPro;
using UnityEngine;
using UnityEngine.SceneManagement;

/// <summary>
/// Tela de loading (Tarefa #16 — "verificação final: tela de morte, loading e
/// save 100%/101%"): overlay full-screen (CanvasGroup, Screen Space - Overlay)
/// usado em qualquer mudança de cena (Opções → "Regressar ao Coração de
/// Gaia"/título, SaveMenuController ao carregar um slot, e
/// PlayerDeathHandler ao reaparecer, se a cena precisar de recarregar).
///
/// Singleton com auto-fallback (mesmo padrão de PlayerProgress/GameVariables —
/// ver Tarefa #15): cria-se automaticamente antes da primeira cena se não
/// existir uma instância configurada num "GameBootstrap".
///
/// Montagem no Editor:
/// - Canvas (Screen Space - Overlay, sortingOrder alto) com um "panelRoot"
///   (Image full-screen preta) + "canvasGroup" no mesmo GameObject.
/// - "loadingText" (TMP_Text, opcional): ex. "A carregar...".
/// - "minDisplayTime": tempo mínimo (s) com o overlay visível, mesmo que a
///   cena carregue mais rápido — evita "flashes" do overlay.
/// </summary>
public class LoadingScreenController : MonoBehaviour
{
    public static LoadingScreenController Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private TMP_Text loadingText;

    [Header("Transição")]
    [Tooltip("Duração do fade in/out do overlay, em segundos.")]
    [SerializeField] private float fadeDuration = 0.25f;

    [Tooltip("Tempo mínimo (s) com o overlay totalmente visível, mesmo que a cena carregue mais rápido.")]
    [SerializeField] private float minDisplayTime = 0.4f;

    [Tooltip("Texto mostrado durante o carregamento (ex: 'A carregar...').")]
    [SerializeField] private string loadingMessage = "A carregar...";

    private bool isAutoFallback;
    private bool isLoading;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        if (canvasGroup != null)
        {
            canvasGroup.alpha = 0f;
            canvasGroup.blocksRaycasts = false;
        }

        if (panelRoot != null) panelRoot.SetActive(false);
        if (loadingText != null) loadingText.text = loadingMessage;
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(LoadingScreenController) + " (Fallback)");
        var instance = go.AddComponent<LoadingScreenController>();
        instance.isAutoFallback = true;
    }

    /// <summary>true enquanto uma cena está a ser carregada através deste controlador.</summary>
    public bool IsLoading => isLoading;

    /// <summary>
    /// Carrega "sceneName" com fade in/out do overlay. "onLoaded" é chamado
    /// depois da cena activar mas ANTES do fade out — útil para reposicionar o
    /// player (ex: PlayerDeathHandler) antes do jogador voltar a ver o ecrã.
    /// </summary>
    public void LoadScene(string sceneName, Action onLoaded = null)
    {
        if (string.IsNullOrEmpty(sceneName))
        {
            Debug.LogWarning("[LoadingScreenController] Nome de cena vazio — não é possível carregar.");
            return;
        }

        if (isLoading) return;

        StartCoroutine(LoadSceneRoutine(sceneName, onLoaded));
    }

    private IEnumerator LoadSceneRoutine(string sceneName, Action onLoaded)
    {
        isLoading = true;

        yield return FadeRoutine(0f, 1f);

        float startTime = Time.unscaledTime;

        var op = SceneManager.LoadSceneAsync(sceneName);
        if (op != null)
        {
            op.allowSceneActivation = false;

            // Espera o carregamento chegar a 90% (Unity fica aqui até activar a cena).
            while (op.progress < 0.9f) yield return null;

            // Garante o tempo mínimo de overlay visível.
            while (Time.unscaledTime - startTime < minDisplayTime) yield return null;

            op.allowSceneActivation = true;
            while (!op.isDone) yield return null;
        }

        onLoaded?.Invoke();

        yield return FadeRoutine(1f, 0f);

        isLoading = false;
    }

    /// <summary>
    /// Mostra o overlay (fade in), executa "duringOverlay" enquanto totalmente
    /// visível e depois esconde (fade out) — sem mudar de cena. Usado pelo
    /// PlayerDeathHandler quando o reaparecimento acontece na MESMA cena (basta
    /// reposicionar o player, sem SceneManager).
    /// </summary>
    public void ShowDuring(Action duringOverlay)
    {
        if (isLoading) return;
        StartCoroutine(ShowDuringRoutine(duringOverlay));
    }

    private IEnumerator ShowDuringRoutine(Action duringOverlay)
    {
        isLoading = true;

        yield return FadeRoutine(0f, 1f);

        float startTime = Time.unscaledTime;
        duringOverlay?.Invoke();

        while (Time.unscaledTime - startTime < minDisplayTime) yield return null;

        yield return FadeRoutine(1f, 0f);

        isLoading = false;
    }

    private IEnumerator FadeRoutine(float from, float to)
    {
        if (canvasGroup == null) yield break;

        if (panelRoot != null) panelRoot.SetActive(true);
        canvasGroup.blocksRaycasts = true;
        canvasGroup.alpha = from;

        if (fadeDuration <= 0f)
        {
            canvasGroup.alpha = to;
        }
        else
        {
            float t = 0f;
            while (t < fadeDuration)
            {
                t += Time.unscaledDeltaTime;
                canvasGroup.alpha = Mathf.Lerp(from, to, t / fadeDuration);
                yield return null;
            }
            canvasGroup.alpha = to;
        }

        if (Mathf.Approximately(to, 0f))
        {
            canvasGroup.blocksRaycasts = false;
            if (panelRoot != null) panelRoot.SetActive(false);
        }
    }
}
